SELECT b.board_id, b.user_id, b.category, b.title, b.content, b.image_url, b.view_count, b.created_at, b.updated_at, u.name AS author_name, CONCAT(h.dong, ' ', h.ho) AS author_unit, (SELECT COUNT(*) FROM comment c WHERE c.board_id = b.board_id AND c.is_deleted = 0) AS comment_count FROM board b JOIN user u ON b.user_id = u.user_id LEFT JOIN household h ON u.household_id = h.household_id WHERE b.is_deleted = 0
AND b.category = #{category}
AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR b.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT b.board_id, b.user_id, b.category, b.title, b.content, b.image_url, b.view_count, b.created_at, b.updated_at, b.is_deleted, u.name AS author_name, CONCAT(h.dong, ' ', h.ho) AS author_unit, (SELECT COUNT(*) FROM comment c WHERE c.board_id = b.board_id AND c.is_deleted = 0) AS comment_count FROM board b JOIN user u ON b.user_id = u.user_id LEFT JOIN household h ON u.household_id = h.household_id WHERE 1=1
AND b.category = #{category}
AND b.is_deleted = #{isDeleted}
ORDER BY b.created_at DESC LIMIT #{size} OFFSET #{offset}

